code = """import json
import re
from collections import defaultdict

# Load the German patents data
patents_file = locals()['var_functions.query_db:86']
with open(patents_file, 'r') as f:
    patents = json.load(f)

print(f'Loading {len(patents)} German patents from 2019...')

# Date parsing
month_map = {
    'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6,
    'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12
}

def get_month(date_str):
    if not date_str:
        return None
    lower = date_str.lower()
    for abbr, num in month_map.items():
        if abbr in lower:
            return num
    return None

# Extract CPC Level 4 codes
def extract_cpc(cpc_data):
    try:
        cpc_list = json.loads(cpc_data)
        codes = []
        for item in cpc_list:
            code = item.get('code', '')
            if code and re.match(r'^[A-HY]\d{2}[A-Z]\d{2,4}/\d{2,4}$', code):
                codes.append(code.split('/')[0])
        return list(set(codes))
    except:
        return []

# Build monthly patent counts
cpc_counts = defaultdict(lambda: defaultdict(int))
h2_patents = 0

for patent in patents:
    grant_date = patent.get('grant_date', '')
    month = get_month(grant_date)
    
    if month and 7 <= month <= 12:  # H2 2019
        h2_patents += 1
        codes = extract_cpc(patent.get('cpc', ''))
        for code in codes:
            cpc_counts[code][month] += 1

print(f'H2 2019 patents: {h2_patents}')
print(f'CPC groups found: {len(cpc_counts)}')

# Prepare results for return
result = {
    'total_patents_analyzed': h2_patents,
    'cpc_groups_found': len(cpc_counts),
    'analysis_period': 'July-December 2019'
}

print('__RESULT__:')
print(json.dumps(result))"""

